solution_code:
#include <stdio.h>

int double_val(int x) { return x * 2; }
int square_val(int x) { return x * x; }

void apply(int *arr, int n, int (*fn)(int)) {
    for (int i = 0; i < n; i++) {
        arr[i] = fn(arr[i]);
    }
}

static int negate(int x) { return -x; }

int main(void) {
    {
        int arr[] = {1, 2, 3};
        apply(arr, 3, double_val);
        printf("%d\n", (int)(arr[0]));
        printf("%d\n", (int)(arr[1]));
        printf("%d\n", (int)(arr[2]));
    }
    {
        int arr[] = {2, 3, 4};
        apply(arr, 3, square_val);
        printf("%d\n", (int)(arr[0]));
        printf("%d\n", (int)(arr[1]));
        printf("%d\n", (int)(arr[2]));
    }
    {
        int arr[] = {-5, 0, 10};
        apply(arr, 3, negate);
        printf("%d\n", (int)(arr[0]));
        printf("%d\n", (int)(arr[1]));
        printf("%d\n", (int)(arr[2]));
    }
    {
        int arr[] = {7};
        apply(arr, 1, double_val);
        printf("%d\n", (int)(arr[0]));
    }
    return 0;
}

